// Helper: convert basic markdown to HTML
function md2html(md) {
  if (!md) return '';
  let html = md
    .replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;')
    .replace(/^### (.+)$/gm, '<h4 style="margin:16px 0 6px;font-size:14px;color:#1e40af;">$1</h4>')
    .replace(/^## (.+)$/gm, '<h3 style="margin:18px 0 8px;font-size:15px;color:#1e40af;">$1</h3>')
    .replace(/^# (.+)$/gm, '<h2 style="margin:0 0 12px;font-size:17px;color:#0f172a;">$1</h2>')
    .replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>')
    .replace(/^(\d+)\. (.+)$/gm, '<div style="margin:4px 0;padding-left:16px;">$1. $2</div>')
    .replace(/\n\n/g, '<br><br>')
    .replace(/\n/g, '<br>');
  return html;
}

const bloggers = $('Query Bloggers').all();
const collaborators = $('Query Collaborators').all();

// Build collaborator map
const collabMap = {};
for (const c of collaborators) collabMap[c.json.id] = c.json;

// Group bloggers by collaborator_id
const grouped = {};
for (const b of bloggers) {
  const cid = b.json.collaborator_id;
  if (!grouped[cid]) grouped[cid] = [];
  grouped[cid].push(b.json);
}

const results = [];
const today = new Date().toISOString().split('T')[0];

for (const [collabId, posts] of Object.entries(grouped)) {
  const collab = collabMap[collabId];
  if (!collab || !collab.email) continue;

  // Separate EN and PT-BR posts (heuristic: PT-BR posts contain Portuguese markers)
  let postEN = '';
  let postPT = '';
  const bloggerIds = [];

  for (const p of posts) {
    bloggerIds.push(p.id);
    const content = p.content || '';
    if (/\b(que|para|como|mais|com|uma|seu|sua|voce|ainda|tambem|ja|nao)\b/i.test(content) && 
        !/\b(the|and|that|this|with|from|have|been)\b/i.test(content.substring(0, 200))) {
      postPT = content;
    } else {
      postEN = content;
    }
  }

  if (!postEN && postPT) { postEN = postPT; postPT = ''; }

  const linkedinRaw = collab.linkedin_improvement || '';
  const linkedinHtml = md2html(linkedinRaw);

  const enSection = postEN ? '<div style="padding:24px 32px;border-bottom:1px solid #e2e8f0;"><div style="font-size:11px;font-weight:600;letter-spacing:1px;text-transform:uppercase;color:#94a3b8;margin-bottom:12px;">YOUR LINKEDIN POST (English)</div><div style="background:#f8fafc;border:1px solid #e2e8f0;border-radius:8px;padding:20px;font-size:14px;line-height:1.8;color:#1e293b;white-space:pre-wrap;font-family:-apple-system,BlinkMacSystemFont,Segoe UI,sans-serif;">' + postEN + '</div><div style="margin-top:12px;font-size:12px;color:#64748b;">Copy the text above and paste on LinkedIn</div></div>' : '';

  const ptSection = postPT ? '<div style="padding:24px 32px;border-bottom:1px solid #e2e8f0;"><div style="font-size:11px;font-weight:600;letter-spacing:1px;text-transform:uppercase;color:#94a3b8;margin-bottom:12px;">SEU POST LINKEDIN (Portugues)</div><div style="background:#f8fafc;border:1px solid #e2e8f0;border-radius:8px;padding:20px;font-size:14px;line-height:1.8;color:#1e293b;white-space:pre-wrap;font-family:-apple-system,BlinkMacSystemFont,Segoe UI,sans-serif;">' + postPT + '</div><div style="margin-top:12px;font-size:12px;color:#64748b;">Copie o texto acima e cole no LinkedIn</div></div>' : '';

  const improvementSection = linkedinHtml ? '<div style="padding:24px 32px;border-bottom:1px solid #e2e8f0;"><div style="font-size:11px;font-weight:600;letter-spacing:1px;text-transform:uppercase;color:#94a3b8;margin-bottom:12px;">SUGESTOES PARA SEU PERFIL LINKEDIN</div><div style="background:#eff6ff;border:1px solid #bfdbfe;border-radius:8px;padding:20px;font-size:13px;line-height:1.7;color:#1e40af;">' + linkedinHtml + '</div></div>' : '';

  const emailHtml = '<!DOCTYPE html><html><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1"></head><body style="margin:0;padding:20px;background:#f4f4f5;font-family:-apple-system,BlinkMacSystemFont,Segoe UI,sans-serif;"><div style="max-width:640px;margin:0 auto;background:#fff;border-radius:10px;overflow:hidden;box-shadow:0 2px 12px rgba(0,0,0,.08);"><div style="background:#0f172a;padding:24px 32px;"><div style="font-size:11px;font-weight:600;letter-spacing:1px;text-transform:uppercase;color:#94a3b8;margin-bottom:6px;">LinkedIn Content &mdash; Luby</div><div style="font-size:22px;font-weight:700;color:#f8fafc;line-height:1.3;">Posts prontos para publicacao</div></div><div style="padding:12px 32px;background:#f8fafc;border-bottom:1px solid #e2e8f0;font-size:12px;color:#64748b;"><strong style="color:#334155">' + (collab.name || '') + '</strong> &middot; ' + (collab.role || '') + ' &middot; ' + today + '</div>' + enSection + ptSection + improvementSection + '<div style="padding:24px 32px;text-align:center;"><div style="font-size:12px;color:#94a3b8;">Gerado automaticamente por Opensquad &middot; Luby Software &middot; ' + today + '</div></div></div></body></html>';

  results.push({
    json: {
      collaborator_id: collabId,
      collaborator_name: collab.name,
      collaborator_email: collab.email,
      blogger_ids: bloggerIds,
      emailSubject: '[Luby LinkedIn] ' + collab.name + ', seus posts estao prontos para publicar',
      emailHtml: emailHtml
    }
  });
}

return results;

const bloggerIds = $json.blogger_ids || [];
const results = [];
for (const id of bloggerIds) {
  results.push({ json: { id: id, submitted_content: true } });
}
return results;
